/// Canonical moorings directory name — the single Rust-side source for the
/// consumer-config root, mirroring bash RBCC_moorings_dir across the language
/// boundary (Rust can't read the shell constant). Rust `const` cannot compose
/// `&str` from another const ref (`concat!` takes only literals), so the
/// bundled path constants (e.g. RBTDRP_RBRR_FILE = "rbmm_moorings/rbrr.env")
/// must repeat the dir literally; `#[test]` drift guards in the rbtdt* modules
/// assert each bundled value `.starts_with(RBTD_MOORINGS_DIR)` so a rename of
/// this const that misses a bundled site fails the test suite.
pub const RBTD_MOORINGS_DIR: &str = "rbmm_moorings";

pub mod rbtdrb_probe;

